+    /// Acquire a lock in a specific directory with timeout (for testing).
+    #[cfg(test)]
+    fn acquire_in_dir_with_timeout(
+        lock_dir: &Path,
+        lock_name: &str,
+        timeout: Duration,
+        operation: &str,
+    ) -> Result<Self> {
+        fs::create_dir_all(lock_dir)
